INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afs70018w9k1ezukcncb', 'journal-of-advanced-research', 'Journal of Advanced Research', 'Журнал передовых исследований', 'Ilg‘or tadqiqotlar jurnali', 'Междисциплинарный рецензируемый журнал открытого доступа Каирского университета, публикующий исследования в области прикладных и естественных наук, медицины, инженерии и смежных дисциплин.', 'Elsevier', 'https://www.sciencedirect.com/journal/journal-of-advanced-research', NULL, '2090-1232', '2090-1224', NULL, '{}', '{Multidisciplinary}', '{Multidisciplinary}', true, false, '2010-2026', 21.7, 18.2, 97, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.775', '2026-07-18 06:49:00.775', 'An interdisciplinary peer-reviewed open access journal of Cairo University publishing research across applied and natural sciences, medicine, engineering, and related fields.', 'Междисциплинарный рецензируемый журнал открытого доступа Каирского университета, публикующий исследования в области прикладных и естественных наук, медицины, инженерии и смежных дисциплин.', 'Qohira universitetining fanlararo taqrizlanadigan ochiq kirish jurnali bo‘lib, amaliy va tabiiy fanlar, tibbiyot, muhandislik hamda turdosh yo‘nalishlardagi tadqiqotlarni nashr etadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afs80019w9k1zbzgmz2j', 'transportation-planning-and-technology', 'Transportation Planning and Technology', 'Планирование транспорта и технологии', 'Transportni rejalashtirish va texnologiya', 'Международный рецензируемый журнал, публикующий исследования по транспортным системам, планированию, моделированию, политике и технологиям, улучшающим пассажирские и грузовые перевозки.', 'Taylor & Francis', 'https://www.tandfonline.com/journals/gtpt20', NULL, '0308-1060', '1029-0354', NULL, '{}', '{"Geography, Planning and Development",Transportation}', '{"Social Sciences"}', true, false, '1972-2026', 3.3, 3.8, 63, 'Q2', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.776', '2026-07-18 06:49:00.776', 'An international peer-reviewed journal publishing research on transport systems, planning, modelling, policy, and technologies that improve passenger and freight transport.', 'Международный рецензируемый журнал, публикующий исследования по транспортным системам, планированию, моделированию, политике и технологиям, улучшающим пассажирские и грузовые перевозки.', 'Yo‘lovchi va yuk tashishni yaxshilovchi transport tizimlari, rejalashtirish, modellashtirish, siyosat va texnologiyalar bo‘yicha tadqiqotlarni chop etuvchi xalqaro taqrizlanadigan jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsa001aw9k1ywvf39d6', 'education-and-information-technologies', 'Education and Information Technologies', 'Образование и информационные технологии', 'Ta’lim va axborot texnologiyalari', 'Журнал, посвящённый пересечению информационных технологий и образования, включая применение вычислительных технологий для улучшения преподавания, обучения и управления образованием.', 'Springer Nature', 'https://link.springer.com/journal/10639', NULL, '1360-2357', '1573-7608', NULL, '{}', '{Education,"Library and Information Sciences"}', '{"Social Sciences"}', true, false, '1996-2002, 2005-2026', 15.5, 17.8, 98, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.778', '2026-07-18 06:49:00.778', 'A journal focused on the intersection of information technology and education, covering computing applications that improve teaching, learning, and educational management.', 'Журнал, посвящённый пересечению информационных технологий и образования, включая применение вычислительных технологий для улучшения преподавания, обучения и управления образованием.', 'Axborot texnologiyalari va ta’lim kesishmasiga bag‘ishlangan jurnal bo‘lib, o‘qitish, o‘rganish va ta’lim boshqaruvini yaxshilashga xizmat qiluvchi texnologik yechimlarni yoritadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsc001bw9k13lbptrfe', 'international-journal-of-educational-research-open', 'International Journal of Educational Research Open', 'Международный журнал открытых исследований в образовании', 'Ta’lim bo‘yicha ochiq tadqiqotlar xalqaro jurnali', 'Рецензируемый журнал открытого доступа, связанный с International Journal of Educational Research, публикующий международные и междисциплинарные исследования в области образования.', 'Elsevier', 'https://www.sciencedirect.com/journal/international-journal-of-educational-research-open', NULL, NULL, '2666-3740', NULL, '{}', '{Education}', '{"Social Sciences"}', true, false, '2020-2026', 6.1, 6.5, 86, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.78', '2026-07-18 06:49:00.78', 'A peer-reviewed open access companion journal to the International Journal of Educational Research, publishing international and interdisciplinary studies in education.', 'Рецензируемый журнал открытого доступа, связанный с International Journal of Educational Research, публикующий международные и междисциплинарные исследования в области образования.', 'International Journal of Educational Research bilan bog‘liq bo‘lgan, ta’lim sohasidagi xalqaro va fanlararo tadqiqotlarni chop etuvchi taqrizlanadigan ochiq kirish jurnali.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsf001cw9k16bpeltm9', 'call-ej', 'CALL-EJ', 'CALL-EJ', 'CALL-EJ', 'Электронный журнал открытого доступа, посвящённый компьютерно-опосредованному обучению языкам и смежным исследованиям в области технологически поддерживаемого языкового образования.', 'The Pacific Association for Computer Assisted Language Learning (PacCALL)', 'https://callej.org/', NULL, NULL, '2187-9036', NULL, '{}', '{"Language and Linguistics","Linguistics and Language","Computer Science Applications"}', '{"Arts and Humanities","Social Sciences","Computer Science"}', true, false, '2013-2026', 2.4, 2, 82, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.783', '2026-07-18 06:49:00.783', 'An open access electronic journal focused on computer-assisted language learning and related research on technology-enhanced language teaching and learning.', 'Электронный журнал открытого доступа, посвящённый компьютерно-опосредованному обучению языкам и смежным исследованиям в области технологически поддерживаемого языкового образования.', 'Kompyuter yordamida til o‘qitish hamda texnologiya asosidagi til ta’limi bo‘yicha tadqiqotlarga bag‘ishlangan ochiq kirishdagi elektron jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsh001dw9k1uuyjqxet', 'scientific-reports', 'Scientific Reports', 'Научные отчёты', 'Ilmiy hisobotlar', 'Крупный журнал открытого доступа издательства Nature Portfolio, публикующий оригинальные исследования в области естественных наук, психологии, медицины и инженерии.', 'Springer Nature', 'https://www.nature.com/srep/', NULL, NULL, '2045-2322', NULL, '{}', '{Multidisciplinary}', '{Multidisciplinary}', true, false, '2011-2026', 6.4, 6.4, 87, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.785', '2026-07-18 06:49:00.785', 'A large-scale open access journal from Nature Portfolio publishing original research across the natural sciences, psychology, medicine, and engineering.', 'Крупный журнал открытого доступа издательства Nature Portfolio, публикующий оригинальные исследования в области естественных наук, психологии, медицины и инженерии.', 'Nature Portfolio nashriyotining yirik ochiq kirish jurnali bo‘lib, tabiiy fanlar, psixologiya, tibbiyot va muhandislik bo‘yicha original tadqiqotlarni nashr etadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsj001ew9k1y058dp46', 'revista-cientifica-de-sistemas-e-informatica', 'Revista Cientifica de Sistemas e Informatica', 'Научный журнал систем и информатики', 'Tizimlar va informatika ilmiy jurnali', 'Журнал открытого доступа Университета Сан-Мартин, публикующий рецензируемые исследования по компьютерным наукам, информационным системам, программной инженерии, искусственному интеллекту и смежным технологиям.', 'Universidad Nacional de San Martín', 'https://revistas.unsm.edu.pe/index.php/rcsi', NULL, NULL, '2709-992X', NULL, '{}', '{"Information Systems","Computer Science Applications","Hardware and Architecture","Computer Science (miscellaneous)"}', '{"Computer Science"}', true, false, '2021-2026', 1.1, 1.2, 25, 'Q3', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.787', '2026-07-18 06:49:00.787', 'An open access journal of Universidad Nacional de San Martín publishing peer-reviewed research in computer science, information systems, software engineering, artificial intelligence, and related technologies.', 'Журнал открытого доступа Университета Сан-Мартин, публикующий рецензируемые исследования по компьютерным наукам, информационным системам, программной инженерии, искусственному интеллекту и смежным технологиям.', 'Universidad Nacional de San Martín nashr etadigan, kompyuter fanlari, axborot tizimlari, dasturiy injiniring, sun’iy intellekt va turdosh texnologiyalar bo‘yicha taqrizlanadigan ochiq kirish jurnalidir.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsl001fw9k1lxiax4j0', 'international-journal-of-electrical-power-and-energy-systems', 'International Journal of Electrical Power and Energy Systems', 'Международный журнал электроэнергетических и энергетических систем', 'Elektr energetikasi va energiya tizimlari xalqaro jurnali', 'Рецензируемый журнал, публикующий исследования по моделированию, анализу и проектированию электроэнергетических и энергетических систем.', 'Elsevier', 'https://www.sciencedirect.com/journal/international-journal-of-electrical-power-and-energy-systems', NULL, '0142-0615', '1879-3517', NULL, '{}', '{"Electrical and Electronic Engineering","Energy Engineering and Power Technology"}', '{Engineering,Energy}', true, false, '1970, 1979-2026', 12.6, 10, 93, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.789', '2026-07-18 06:49:00.789', 'A peer-reviewed journal publishing research that advances the modelling, analysis, and design of electrical power and energy systems.', 'Рецензируемый журнал, публикующий исследования по моделированию, анализу и проектированию электроэнергетических и энергетических систем.', 'Elektr energetikasi va energiya tizimlarini modellashtirish, tahlil qilish va loyihalash bo‘yicha tadqiqotlarni chop etuvchi taqrizlanadigan jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afoz0000w9k1shsawusf', 'russian-language-studies', 'Russian Language Studies', 'Исследования русского языка', 'Rus tili tadqiqotlari', 'Рецензируемый журнал по русскому языку и методике преподавания русского как иностранного, неродного и родного языка. Публикует исследования по лингвистике, лингводидактике и функционированию русского языка в разных социокультурных контекстах.', 'RUDN University', 'https://journals.rudn.ru/russian-language-studies', NULL, '2618-8163', '2618-8171', NULL, '{}', '{"Language and Linguistics","Linguistics and Language",Education}', '{"Arts and Humanities","Social Sciences"}', true, false, '2018-2026', 1.3, 1.1, 72, 'Q2', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.659', '2026-07-18 06:49:00.659', 'A peer-reviewed journal focused on the Russian language and the teaching of Russian as a foreign, non-native, and native language. It publishes research in linguistics, linguodidactics, and the use of Russian in diverse sociocultural contexts.', 'Рецензируемый журнал по русскому языку и методике преподавания русского как иностранного, неродного и родного языка. Публикует исследования по лингвистике, лингводидактике и функционированию русского языка в разных социокультурных контекстах.', 'Rus tili va rus tilini xorijiy, ona bo‘lmagan hamda ona tili sifatida o‘qitish metodikasiga bag‘ishlangan taqrizdan o‘tuvchi jurnal. Unda lingvistika, lingvodidaktika va rus tilining turli ijtimoiy-madaniy sharoitlardagi qo‘llanilishiga oid tadqiqotlar chop etiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afpb0001w9k16qx68mzu', 'russian-journal-of-linguistics', 'Russian Journal of Linguistics', 'Российский журнал лингвистики', 'Rossiya lingvistika jurnali', 'Международный рецензируемый журнал по лингвистике и смежным дисциплинам. Публикует исследования по языку, культуре, когниции и коммуникации, включая социолингвистику, прагматику, межкультурную коммуникацию и переводоведение.', 'RUDN University', 'https://journals.rudn.ru/linguistics', NULL, '2687-0088', '2686-8024', NULL, '{}', '{"Language and Linguistics","Linguistics and Language"}', '{"Arts and Humanities","Social Sciences"}', true, false, '2018-2026', 3.2, 3.2, 88, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.671', '2026-07-18 06:49:00.671', 'An international peer-reviewed journal in linguistics and related fields. It publishes research on language, culture, cognition, and communication, including sociolinguistics, pragmatics, intercultural communication, and translation studies.', 'Международный рецензируемый журнал по лингвистике и смежным дисциплинам. Публикует исследования по языку, культуре, когниции и коммуникации, включая социолингвистику, прагматику, межкультурную коммуникацию и переводоведение.', 'Tilshunoslik va unga yaqin yo‘nalishlarga bag‘ishlangan xalqaro taqrizli jurnal. Unda til, madaniyat, kognitsiya va kommunikatsiya, jumladan sotsiolingvistika, pragmatika, madaniyatlararo muloqot va tarjimashunoslik bo‘yicha tadqiqotlar chop etiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afpe0002w9k1n3ndimm1', 'world-journal-for-pediatric-and-congenital-heart-surgery', 'World Journal for Pediatric and Congenital Heart Surgery', 'Всемирный журнал детской и врожденной кардиохирургии', 'Pediatrik va tug‘ma yurak jarrohligi bo‘yicha jahon jurnali', 'Рецензируемый журнал, посвященный развитию и распространению знаний в области детской и врожденной кардиохирургии. Охватывает хирургические, клинические и образовательные аспекты лечения врожденных заболеваний сердца у детей.', 'SAGE', 'https://journals.sagepub.com/home/pch', NULL, '2150-1351', '2150-136X', NULL, '{}', '{Surgery,"Pediatrics, Perinatology and Child Health","Cardiology and Cardiovascular Medicine"}', '{Medicine}', true, false, '2010-2026', 1.7, 1.4, 46, 'Q3', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.674', '2026-07-18 06:49:00.674', 'A peer-reviewed journal dedicated to the advancement and dissemination of knowledge in pediatric and congenital heart surgery. It covers surgical, clinical, and educational aspects of care for congenital heart disease in children.', 'Рецензируемый журнал, посвященный развитию и распространению знаний в области детской и врожденной кардиохирургии. Охватывает хирургические, клинические и образовательные аспекты лечения врожденных заболеваний сердца у детей.', 'Bolalar va tug‘ma yurak jarrohligi sohasidagi bilimlarni rivojlantirish va tarqatishga bag‘ishlangan taqrizli jurnal. U bolalardagi tug‘ma yurak kasalliklarini davolashning jarrohlik, klinik va ta’lim jihatlarini qamrab oladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afph0003w9k1wzh0urk3', 'transportation-research-procedia', 'Transportation Research Procedia', 'Материалы конференций по транспортным исследованиям', 'Transport tadqiqotlari bo‘yicha konferensiya materiallari', 'Open access серия, публикующая полные комплекты материалов научных конференций по транспортным исследованиям. Ориентирована на быстрое и широкое распространение материалов конференций в области транспорта и мобильности.', 'Elsevier', 'https://www.sciencedirect.com/journal/transportation-research-procedia', NULL, '2352-1457', '2352-1465', NULL, '{}', '{Transportation}', '{"Social Sciences"}', true, false, '2014-2026', 2.6, 1.9, 39, 'Q3', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.677', '2026-07-18 06:49:00.677', 'An open access publication series focused entirely on publishing complete sets of conference proceedings in transportation research. It is designed for rapid and wide dissemination of conference outputs in transport and mobility.', 'Open access серия, публикующая полные комплекты материалов научных конференций по транспортным исследованиям. Ориентирована на быстрое и широкое распространение материалов конференций в области транспорта и мобильности.', 'Transport tadqiqotlariga oid ilmiy konferensiyalar materiallarining to‘liq to‘plamlarini chop etuvchi open access nashrlar seriyasi. U transport va mobillik sohasidagi konferensiya ishlarini tez va keng tarqatishga yo‘naltirilgan.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afpk0004w9k162q8qjy1', 'hepatology-communications', 'Hepatology Communications', 'Сообщения по гепатологии', 'Gepatologiya bo‘yicha xabarlar', 'Рецензируемый онлайн-журнал открытого доступа для быстрого распространения высококачественных фундаментальных, трансляционных и клинических исследований по гепатологии.', 'Wolters Kluwer Health', 'https://journals.lww.com/hepcomm', NULL, NULL, '2471-254X', NULL, '{}', '{Hepatology}', '{Medicine}', true, false, '2017-2026', 11, 9.5, 85, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.68', '2026-07-18 06:49:00.68', 'A peer-reviewed, online-only open access journal for the rapid dissemination of high-quality basic, translational, and clinical research in hepatology.', 'Рецензируемый онлайн-журнал открытого доступа для быстрого распространения высококачественных фундаментальных, трансляционных и клинических исследований по гепатологии.', 'Gepatologiya bo‘yicha yuqori sifatli fundamental, translyatsion va klinik tadqiqotlarni tez tarqatishga mo‘ljallangan taqrizli, faqat onlayn open access jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afpo0005w9k1n42769em', 'veterinary-sciences', 'Veterinary Sciences', 'Ветеринарные науки', 'Veterinariya fanlari', 'Международный междисциплинарный open access журнал по ветеринарии. Публикует исследования по профилактике, диагностике и лечению заболеваний, нарушений и травм у животных, а также по широкому кругу направлений ветеринарной медицины.', 'MDPI', 'https://www.mdpi.com/journal/vetsci', NULL, NULL, '2306-7381', NULL, '{}', '{"General Veterinary"}', '{Veterinary}', true, false, '2014-2026', 3.9, 3.5, 82, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.684', '2026-07-18 06:49:00.684', 'An international interdisciplinary open access journal in veterinary science. It publishes research on the prevention, diagnosis, and treatment of diseases, disorders, and injuries in animals across a broad range of veterinary fields.', 'Международный междисциплинарный open access журнал по ветеринарии. Публикует исследования по профилактике, диагностике и лечению заболеваний, нарушений и травм у животных, а также по широкому кругу направлений ветеринарной медицины.', 'Veterinariya sohasidagi xalqaro fanlararo open access jurnal. Unda hayvonlardagi kasalliklar, buzilishlar va shikastlanishlarning oldini olish, diagnostikasi va davolashiga oid tadqiqotlar, shuningdek veterinariya tibbiyotining keng yo‘nalishlari bo‘yicha ishlar chop etiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afpr0006w9k1of4w8iqg', 'neurorehabilitation-and-neural-repair', 'Neurorehabilitation and Neural Repair', 'Нейрореабилитация и восстановление нервной системы', 'Neyroreabilitatsiya va asab tizimini tiklash', 'Ведущий международный рецензируемый журнал, публикующий исследования по функциональному восстановлению после поражений нервной системы и длительной неврологической инвалидности. Охватывает инсульт, рассеянный склероз, ДЦП, болезнь Паркинсона, деменцию, черепно-мозговые и спинальные травмы.', 'SAGE', 'https://journals.sagepub.com/home/nnr', NULL, '1545-9683', '1552-6844', NULL, '{}', '{Rehabilitation,Neurology,"Neurology (clinical)"}', '{Medicine,Neuroscience}', true, false, '1987-2026', 6.9, 5.9, 97, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.687', '2026-07-18 06:49:00.687', 'A leading international peer-reviewed journal publishing research on functional recovery from neural injury and long-term neurological disability. It covers stroke, multiple sclerosis, cerebral palsy, Parkinson’s disease, dementia, brain injury, and spinal cord injury.', 'Ведущий международный рецензируемый журнал, публикующий исследования по функциональному восстановлению после поражений нервной системы и длительной неврологической инвалидности. Охватывает инсульт, рассеянный склероз, ДЦП, болезнь Паркинсона, деменцию, черепно-мозговые и спинальные травмы.', 'Asab tizimi shikastlanishidan keyingi funksional tiklanish va uzoq muddatli nevrologik nogironlik bo‘yicha tadqiqotlarni chop etuvchi yetakchi xalqaro taqrizli jurnal. U insult, ko‘p skleroz, bolalar serebral falaji, Parkinson kasalligi, demensiya hamda bosh va orqa miya shikastlanishlarini qamrab oladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afpu0007w9k1kcq2snib', 'journal-of-natural-products', 'Journal of Natural Products', 'Журнал природных продуктов', 'Tabiiy mahsulotlar jurnali', 'Международный журнал, публикующий высокоимпактные исследования по химии и биологии низкомолекулярных природных соединений. Охватывает структуру, биоактивность, функции, биосинтез и получение природных продуктов, а также их связи с фармакологией и химической биологией.', 'American Chemical Society', 'https://pubs.acs.org/journal/jnprdf', NULL, '0163-3864', '1520-6025', NULL, '{}', '{"Complementary and Alternative Medicine","Organic Chemistry",Pharmacology,"Pharmaceutical Science","Drug Discovery"}', '{Medicine,Chemistry,"Pharmacology, Toxicology and Pharmaceutics"}', true, false, '1949, 1971, 1973, or 1978-2026', 6.3, 5.1, 85, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.69', '2026-07-18 06:49:00.69', 'An international journal publishing rigorous, high-impact research on the chemistry and biology of natural product small molecules. It covers structure, bioactivity, function, biosynthesis, production, and related work in pharmacology, analytical chemistry, and chemical biology.', 'Международный журнал, публикующий высокоимпактные исследования по химии и биологии низкомолекулярных природных соединений. Охватывает структуру, биоактивность, функции, биосинтез и получение природных продуктов, а также их связи с фармакологией и химической биологией.', 'Tabiiy kichik molekulali birikmalarning kimyosi va biologiyasiga oid yuqori darajadagi tadqiqotlarni chop etuvchi xalqaro jurnal. U tabiiy mahsulotlarning tuzilishi, biofaolligi, funksiyasi, biosintezi va olinishi, shuningdek ularning farmakologiya hamda kimyoviy biologiya bilan bog‘liqligini qamrab oladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afpx0008w9k1t3nelzdj', 'animal-microbiome', 'Animal Microbiome', 'Микробиом животных', 'Hayvonlar mikrobiomi', 'Журнал публикует исследования по микробиому домашних и диких животных с акцентом на функциональное понимание микробных сообществ и их взаимодействия с организмом хозяина.', 'Springer Nature', 'https://animalmicrobiome.biomedcentral.com/', NULL, NULL, '2524-4671', NULL, '{}', '{"Veterinary (miscellaneous)","Animal Science and Zoology","Agricultural and Biological Sciences (miscellaneous)","Microbiology (medical)"}', '{Veterinary,"Agricultural and Biological Sciences",Medicine}', true, false, '2019-2026', 6.9, 5.2, 96, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.693', '2026-07-18 06:49:00.693', 'The journal publishes animal microbiome research relating to domestic and non-domestic animals, with an emphasis on moving beyond diversity measures toward a functional understanding of host-associated microbiomes.', 'Журнал публикует исследования по микробиому домашних и диких животных с акцентом на функциональное понимание микробных сообществ и их взаимодействия с организмом хозяина.', 'Jurnal uy va yovvoyi hayvonlar mikrobiomi bo‘yicha tadqiqotlarni, ayniqsa mikrob jamoalari va ularning xo‘jayin organizmi bilan o‘zaro ta’sirini funksional tushuntirishga qaratilgan ishlarni chop etadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afq00009w9k1174hb809', 'fetal-and-pediatric-pathology', 'Fetal and Pediatric Pathology', 'Фетальная и педиатрическая патология', 'Fetal va pediatrik patologiya', 'Международный журнал, публикующий исследования и обзоры по заболеваниям эмбриона, новорождённых, детей и подростков. Особое внимание уделяется молекулярным и патогенетическим аспектам пренатальной, перинатальной и детской патологии.', 'Taylor & Francis', 'https://www.tandfonline.com/journals/ipdp20', NULL, '1551-3815', '1551-3823', NULL, '{}', '{"Pediatrics, Perinatology and Child Health","Pathology and Forensic Medicine"}', '{Medicine}', true, false, '1983-1998, 2000-2001, 2003-2026', 1.9, 1.4, 49, 'Q3', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.696', '2026-07-18 06:49:00.696', 'An international journal publishing research and reviews on diseases of the embryo, newborns, children, and adolescents. It emphasizes molecular and pathogenetic aspects of prenatal, perinatal, and pediatric pathology.', 'Международный журнал, публикующий исследования и обзоры по заболеваниям эмбриона, новорождённых, детей и подростков. Особое внимание уделяется молекулярным и патогенетическим аспектам пренатальной, перинатальной и детской патологии.', 'Embriyon, yangi tug‘ilgan chaqaloqlar, bolalar va o‘smirlardagi kasalliklarga oid tadqiqotlar va sharhlarni chop etuvchi xalqaro jurnal. Unda prenatal, perinatal va bolalar patologiyasining molekulyar hamda patogenetik jihatlariga alohida e’tibor qaratiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afq4000aw9k1sizwvihf', '3-biotech', '3 Biotech', '3 Biotech', '3 Biotech', 'Междисциплинарный журнал по биотехнологии и смежным направлениям, публикующий исследования на стыке биологических, сельскохозяйственных и экологических наук.', 'Springer Nature', 'https://link.springer.com/journal/13205', NULL, '2190-572X', '2190-5738', NULL, '{}', '{"Agricultural and Biological Sciences (miscellaneous)","Environmental Science (miscellaneous)",Biotechnology}', '{"Agricultural and Biological Sciences","Environmental Science","Biochemistry, Genetics and Molecular Biology"}', true, false, '2011-2026', 5.7, 4.8, 85, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.7', '2026-07-18 06:49:00.7', 'An interdisciplinary journal in biotechnology and related fields, publishing research at the interface of biological, agricultural, and environmental sciences.', 'Междисциплинарный журнал по биотехнологии и смежным направлениям, публикующий исследования на стыке биологических, сельскохозяйственных и экологических наук.', 'Biotexnologiya va unga yaqin yo‘nalishlarga bag‘ishlangan fanlararo jurnal bo‘lib, biologik, qishloq xo‘jaligi va ekologik fanlar kesishmasidagi tadqiqotlarni chop etadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afq7000bw9k1vel4ictq', 'journal-of-shipping-and-trade', 'Journal of Shipping and Trade', 'Журнал судоходства и торговли', 'Kema qatnovi va savdo jurnali', 'Журнал открытого доступа, посвящённый практике и исследованиям в области судоходства, глобальной торговли, портового менеджмента и управления транспортом.', 'Springer Nature', 'https://jshippingandtrade.springeropen.com/', NULL, NULL, '2364-4575', NULL, '{}', '{"General Economics, Econometrics and Finance","General Business, Management and Accounting",Transportation}', '{"Economics, Econometrics and Finance","Business, Management and Accounting","Social Sciences"}', true, false, '2023-2026', 4.6, 5.4, 81, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.703', '2026-07-18 06:49:00.703', 'An open access journal focused on research and practice in shipping, global trade, port management, and transportation management.', 'Журнал открытого доступа, посвящённый практике и исследованиям в области судоходства, глобальной торговли, портового менеджмента и управления транспортом.', 'Open access jurnal bo‘lib, unda kema qatnovi, global savdo, port boshqaruvi va transport menejmenti sohasidagi amaliyot hamda tadqiqotlar yoritiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afqd000cw9k17nsda0zp', 'journal-of-obesity-and-metabolic-syndrome', 'Journal of Obesity and Metabolic Syndrome', 'Журнал ожирения и метаболического синдрома', 'Semizlik va metabolik sindrom jurnali', 'Рецензируемый журнал, посвящённый исследованиям по ожирению, метаболическому синдрому и связанным нарушениям обмена веществ. Публикует клинические и научные работы, направленные на улучшение профилактики, диагностики и лечения этих состояний.', 'Korean Society for the Study of Obesity', 'https://www.jomes.org/', NULL, '2508-6235', '2508-7576', NULL, '{}', '{"Endocrinology, Diabetes and Metabolism"}', '{Medicine}', true, false, '2017-2026', 14.4, 14.5, 93, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.709', '2026-07-18 06:49:00.709', 'A peer-reviewed journal devoted to obesity, metabolic syndrome, and related metabolic disorders. It publishes clinical and scientific work aimed at improving prevention, diagnosis, and treatment in this field.', 'Рецензируемый журнал, посвящённый исследованиям по ожирению, метаболическому синдрому и связанным нарушениям обмена веществ. Публикует клинические и научные работы, направленные на улучшение профилактики, диагностики и лечения этих состояний.', 'Semizlik, metabolik sindrom va ular bilan bog‘liq modda almashinuvi buzilishlariga bag‘ishlangan taqrizli jurnal. Unda ushbu holatlarning oldini olish, diagnostikasi va davolashini yaxshilashga qaratilgan klinik hamda ilmiy ishlar chop etiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afqi000dw9k1cdhgerl7', 'journal-of-clinical-microbiology', 'Journal of Clinical Microbiology', 'Журнал клинической микробиологии', 'Klinik mikrobiologiya jurnali', 'Журнал публикует актуальные исследования по лабораторной диагностике и ведению инфекций у человека и животных. Основной фокус — клиническая микробиология, диагностика патогенов и вопросы антимикробной устойчивости.', 'American Society for Microbiology', 'https://journals.asm.org/journal/jcm', NULL, '0095-1137', '1098-660X', NULL, '{}', '{"Microbiology (medical)"}', '{Medicine}', true, false, '1975-2026', 8.1, 6.9, 81, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.714', '2026-07-18 06:49:00.714', 'The journal publishes current research related to the laboratory diagnosis and management of human and animal infections. Its main focus is clinical microbiology, pathogen detection, and antimicrobial resistance.', 'Журнал публикует актуальные исследования по лабораторной диагностике и ведению инфекций у человека и животных. Основной фокус — клиническая микробиология, диагностика патогенов и вопросы антимикробной устойчивости.', 'Jurnal odam va hayvonlardagi infeksiyalarni laboratoriya diagnostikasi va boshqaruviga oid dolzarb tadqiqotlarni chop etadi. Asosiy yo‘nalishlari klinik mikrobiologiya, patogenlar diagnostikasi va antimikrob qarshilik masalalaridir.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afqk000ew9k1hn8jb2pq', 'applied-linguistics', 'Applied Linguistics', 'Прикладная лингвистика', 'Amaliy tilshunoslik', 'Журнал публикует исследования языка, связанные с реальными практическими проблемами. Он ориентирован на междисциплинарные и теоретически обоснованные подходы в прикладной лингвистике.', 'Oxford University Press', 'https://academic.oup.com/applij', NULL, '0142-6001', '1477-450X', NULL, '{}', '{"Language and Linguistics","Linguistics and Language",Communication}', '{"Arts and Humanities","Social Sciences"}', true, false, '1980-2026', 10.3, 10.2, 98, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.716', '2026-07-18 06:49:00.716', 'The journal publishes research on language with relevance to real-world issues. It promotes principled, interdisciplinary approaches in applied linguistics.', 'Журнал публикует исследования языка, связанные с реальными практическими проблемами. Он ориентирован на междисциплинарные и теоретически обоснованные подходы в прикладной лингвистике.', 'Jurnal tilga oid real amaliy muammolar bilan bog‘liq tadqiqotlarni chop etadi. U amaliy tilshunoslikda fanlararo va nazariy jihatdan asoslangan yondashuvlarga yo‘naltirilgan.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afqm000fw9k1nx9o1jtu', 'european-journal-of-transport-and-infrastructure-research', 'European Journal of Transport and Infrastructure Research', 'Европейский журнал исследований транспорта и инфраструктуры', 'Transport va infratuzilma tadqiqotlari bo‘yicha Yevropa jurnali', 'Рецензируемый open access журнал по транспорту и инфраструктуре, специализирующийся на поведенческих, организационных, экономических и политических аспектах планирования и функционирования транспортных систем.', 'TU Delft', 'https://journals.open.tudelft.nl/ejtir', NULL, '1567-7133', '1567-7141', NULL, '{}', '{"Urban Studies","Geography, Planning and Development",Transportation}', '{"Social Sciences"}', true, false, '2008-2026', 3.1, 2.5, 68, 'Q2', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.718', '2026-07-18 06:49:00.718', 'A peer-reviewed open access journal specializing in the behavioral, organizational, economic, and public-policy dimensions of planning and operating transport systems and infrastructure.', 'Рецензируемый open access журнал по транспорту и инфраструктуре, специализирующийся на поведенческих, организационных, экономических и политических аспектах планирования и функционирования транспортных систем.', 'Transport va infratuzilma bo‘yicha taqrizli open access jurnal bo‘lib, transport tizimlarini rejalashtirish va boshqarishning xulq-atvor, tashkiliy, iqtisodiy va siyosiy jihatlariga ixtisoslashgan.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afqp000gw9k11bdy9001', 'transport-problems', 'Transport Problems', 'Транспортные проблемы', 'Transport muammolari', 'Междисциплинарный журнал по транспортным исследованиям, логистике, экономике и технологиям транспорта. Публикует работы, связанные с функционированием и развитием транспортных систем.', 'Silesian University of Technology', 'http://transportproblems.polsl.pl/default.aspx', NULL, '1896-0596', '2300-861X', NULL, '{}', '{"Automotive Engineering","Mechanical Engineering",Transportation}', '{Engineering,"Social Sciences"}', true, false, '2012-2026', 1.3, 1.2, 29, 'Q3', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.721', '2026-07-18 06:49:00.721', 'An interdisciplinary journal covering transport research, logistics, transport economics, and transport technologies, with a focus on the functioning and development of transport systems.', 'Междисциплинарный журнал по транспортным исследованиям, логистике, экономике и технологиям транспорта. Публикует работы, связанные с функционированием и развитием транспортных систем.', 'Transport tadqiqotlari, logistika, iqtisodiyot va transport texnologiyalariga bag‘ishlangan fanlararo jurnal. U transport tizimlarining faoliyati va rivojlanishiga oid ishlarni chop etadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afqr000hw9k177cbtlsg', 'research-result-theoretical-and-applied-linguistics', 'Research Result. Theoretical and Applied Linguistics', 'Научный результат. Теоретическая и прикладная лингвистика', 'Ilmiy natija. Nazariy va amaliy tilshunoslik', 'Международный рецензируемый журнал открытого доступа, посвящённый теоретической и прикладной лингвистике. Публикует исследования по языку, дискурсу, переводу, грамматике и другим направлениям современного языкознания.', 'Belgorod State National Research University', 'http://rrlinguistics.ru/', NULL, NULL, '2313-8912', NULL, '{}', '{"Literature and Literary Theory","Language and Linguistics","Linguistics and Language"}', '{"Arts and Humanities","Social Sciences"}', true, false, '2019-2026', 1.3, 1.5, 95, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.723', '2026-07-18 06:49:00.723', 'An international peer-reviewed open access journal devoted to theoretical and applied linguistics. It publishes research on language, discourse, translation, grammar, and other areas of contemporary linguistic inquiry.', 'Международный рецензируемый журнал открытого доступа, посвящённый теоретической и прикладной лингвистике. Публикует исследования по языку, дискурсу, переводу, грамматике и другим направлениям современного языкознания.', 'Nazariy va amaliy tilshunoslikka bag‘ishlangan xalqaro taqrizli open access jurnal. Unda til, diskurs, tarjima, grammatika va zamonaviy tilshunoslikning boshqa yo‘nalishlari bo‘yicha tadqiqotlar chop etiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afqu000iw9k1ili1iz7g', 'hernia', 'Hernia', 'Грыжа', 'Churra', 'Журнал посвящён клиническим исследованиям и фундаментальным работам по паховым, внутренним, абдоминальным, диафрагмальным и промежностным грыжам, а также хирургии брюшной стенки.', 'Springer Nature', 'https://link.springer.com/journal/10029', NULL, '1265-4906', '1248-9204', NULL, '{}', '{Surgery}', '{Medicine}', true, false, '1999-2026', 4.6, 3.6, 84, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.726', '2026-07-18 06:49:00.726', 'The journal promotes clinical studies and basic research related to groin hernias, internal hernias, the abdominal wall, the diaphragm, and the perineum.', 'Журнал посвящён клиническим исследованиям и фундаментальным работам по паховым, внутренним, абдоминальным, диафрагмальным и промежностным грыжам, а также хирургии брюшной стенки.', 'Jurnal chov, ichki, qorin devori, diafragma va oraliq churralari hamda qorin devori jarrohligiga oid klinik va fundamental tadqiqotlarga bag‘ishlangan.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afqw000jw9k16e2w8sgx', 'journal-of-music-teacher-education', 'Journal of Music Teacher Education', 'Журнал музыкально-педагогического образования', 'Musiqa o‘qituvchisi ta’limi jurnali', 'Рецензируемый онлайн-журнал, посвящённый вопросам подготовки учителей музыки. Публикует исследовательские и обзорные материалы по музыкальному образованию и педагогической практике.', 'SAGE', 'https://journals.sagepub.com/home/jmt', NULL, '1057-0837', '1945-0079', NULL, '{}', '{Music,Education}', '{"Arts and Humanities","Social Sciences"}', true, false, '1991-2026', 2, 2, 89, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.728', '2026-07-18 06:49:00.728', 'A peer-reviewed online journal focused on issues in music teacher education. It publishes research and professional scholarship related to music education and teaching practice.', 'Рецензируемый онлайн-журнал, посвящённый вопросам подготовки учителей музыки. Публикует исследовательские и обзорные материалы по музыкальному образованию и педагогической практике.', 'Musiqa o‘qituvchilarini tayyorlash masalalariga bag‘ishlangan taqrizli onlayn jurnal. Unda musiqiy ta’lim va pedagogik amaliyot bo‘yicha tadqiqot hamda sharh materiallari chop etiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afqy000kw9k1ekgb09wh', 'international-journal-of-educational-technology-in-higher-education', 'International Journal of Educational Technology in Higher Education', 'Международный журнал образовательных технологий в высшем образовании', 'Oliy ta’limda ta’lim texnologiyalari bo‘yicha xalqaro jurnal', 'Рецензируемый журнал, публикующий актуальные исследования по образовательным технологиям в высшем образовании. Особое внимание уделяется инновационным подходам к использованию технологий для улучшения обучения, дизайна курсов и образовательных результатов.', 'Springer Nature', 'https://link.springer.com/journal/41239', NULL, NULL, '2365-9440', NULL, '{}', '{Education,"Computer Science Applications"}', '{"Social Sciences","Computer Science"}', true, false, '2016-2026', 48.4, 64.6, 99, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.73', '2026-07-18 06:49:00.73', 'A peer-reviewed journal featuring current research on educational technology in higher education. It emphasizes innovative approaches to using technology to enhance learning, course design, and educational outcomes.', 'Рецензируемый журнал, публикующий актуальные исследования по образовательным технологиям в высшем образовании. Особое внимание уделяется инновационным подходам к использованию технологий для улучшения обучения, дизайна курсов и образовательных результатов.', 'Oliy ta’limdagi ta’lim texnologiyalariga oid dolzarb tadqiqotlarni chop etuvchi taqrizli jurnal. Unda ta’lim natijalari, kurs dizayni va o‘qitishni yaxshilash uchun texnologiyalardan innovatsion foydalanishga alohida e’tibor qaratiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afqz000lw9k16pqlpz5t', 'social-psychology-of-education', 'Social Psychology of Education', 'Социальная психология образования', 'Ta’limning ijtimoiy psixologiyasi', 'Междисциплинарный журнал, направленный на понимание человеческого поведения в образовании. Объединяет подходы психологии, социологии и педагогики для изучения социальных и психологических процессов в образовательной среде.', 'Springer Nature', 'https://link.springer.com/journal/11218', NULL, '1381-2890', '1573-1928', NULL, '{}', '{"Sociology and Political Science",Education,"Developmental and Educational Psychology","Social Psychology"}', '{"Social Sciences",Psychology}', true, false, '1996-2026', 5.1, 4.9, 86, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.731', '2026-07-18 06:49:00.731', 'A multidisciplinary journal aimed at understanding human behavior in education. It draws on psychology, sociology, and education to examine social and psychological processes in educational settings.', 'Междисциплинарный журнал, направленный на понимание человеческого поведения в образовании. Объединяет подходы психологии, социологии и педагогики для изучения социальных и психологических процессов в образовательной среде.', 'Ta’limdagi inson xulq-atvorini tushunishga qaratilgan fanlararo jurnal. U ta’lim muhitidagi ijtimoiy va psixologik jarayonlarni o‘rganish uchun psixologiya, sotsiologiya va pedagogika yondashuvlarini birlashtiradi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afr1000mw9k1koymysvj', 'asia-pacific-journal-of-tourism-research', 'Asia Pacific Journal of Tourism Research', 'Азиатско-Тихоокеанский журнал исследований туризма', 'Osiyo-Tinch okeani turizm tadqiqotlari jurnali', 'Международный журнал, посвящённый исследованиям туризма в Азиатско-Тихоокеанском регионе и за его пределами. Публикует работы по развитию туризма, туристскому поведению, планированию и управлению в сфере гостеприимства.', 'Taylor & Francis', 'https://www.tandfonline.com/journals/rapt20', NULL, '1094-1665', '1741-6507', NULL, '{}', '{"Geography, Planning and Development","Tourism, Leisure and Hospitality Management"}', '{"Social Sciences","Business, Management and Accounting"}', true, false, '2003-2026', 6.1, 6.5, 83, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.733', '2026-07-18 06:49:00.733', 'An international journal devoted to tourism research in the Asia-Pacific region and beyond. It publishes work on tourism development, tourist behavior, planning, and hospitality management.', 'Международный журнал, посвящённый исследованиям туризма в Азиатско-Тихоокеанском регионе и за его пределами. Публикует работы по развитию туризма, туристскому поведению, планированию и управлению в сфере гостеприимства.', 'Osiyo-Tinch okeani mintaqasi va undan tashqaridagi turizm tadqiqotlariga bag‘ishlangan xalqaro jurnal. Unda turizm rivoji, sayyohlar xulqi, rejalashtirish va mehmondo‘stlik boshqaruviga oid ishlar chop etiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afr3000nw9k1jiit51ws', 'regional-studies', 'Regional Studies', 'Региональные исследования', 'Hududiy tadqiqotlar', 'Ведущий международный журнал по теории, эмпирическому анализу и политическим дебатам в области региональных исследований. Публикует исследования экономических, социальных, политических и экологических аспектов городских и региональных изменений.', 'Taylor & Francis', 'https://www.tandfonline.com/journals/cres20', NULL, '0034-3404', '1360-0591', NULL, '{}', '{"General Social Sciences","General Environmental Science"}', '{"Social Sciences","Environmental Science"}', true, false, '1967-2026', 10, 9.5, 97, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.735', '2026-07-18 06:49:00.735', 'A leading international journal covering theory development, empirical analysis, and policy debate in regional studies. It publishes research on the economic, social, political, and environmental dimensions of urban and regional change.', 'Ведущий международный журнал по теории, эмпирическому анализу и политическим дебатам в области региональных исследований. Публикует исследования экономических, социальных, политических и экологических аспектов городских и региональных изменений.', 'Hududiy tadqiqotlar sohasida nazariya, empirik tahlil va siyosiy munozaralarga bag‘ishlangan yetakchi xalqaro jurnal. Unda shahar va hududiy o‘zgarishlarning iqtisodiy, ijtimoiy, siyosiy hamda ekologik jihatlariga oid tadqiqotlar chop etiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afr4000ow9k19dgfolo7', 'contact-dermatitis', 'Contact Dermatitis', 'Контактный дерматит', 'Kontakt dermatiti', 'Дерматологический журнал, ориентированный прежде всего на клиницистов и посвящённый аллергическим и раздражающим формам контактного дерматита, профессиональному и потребительскому дерматиту.', 'John Wiley & Sons', 'https://www.wiley.com/journals/Contact+Dermatitis-p-b16000536', NULL, '0105-1873', '1600-0536', NULL, '{}', '{Dermatology,"Immunology and Allergy"}', '{Medicine}', true, false, '1975-2026', 4.4, 3.2, 76, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.736', '2026-07-18 06:49:00.736', 'A dermatology journal primarily for clinicians, focusing on allergic and irritant contact dermatitis, occupational dermatitis, and consumer dermatitis.', 'Дерматологический журнал, ориентированный прежде всего на клиницистов и посвящённый аллергическим и раздражающим формам контактного дерматита, профессиональному и потребительскому дерматиту.', 'Asosan klinitsistlarga mo‘ljallangan dermatologiya jurnali bo‘lib, allergik va irritant kontakt dermatiti, kasbiy hamda iste’molchi dermatitiga bag‘ishlangan.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afr6000pw9k1q7j8mlrz', 'journal-of-family-psychology', 'Journal of Family Psychology', 'Журнал семейной психологии', 'Oila psixologiyasi jurnali', 'Ведущий журнал по семейным исследованиям, рассматривающий семейные отношения с системной, developmental и культурной точек зрения. Публикует работы о партнёрских, родительских и семейных отношениях, а также о социальных вызовах, с которыми сталкиваются семьи.', 'American Psychological Association', 'https://www.apa.org/pubs/journals/fam', NULL, '0893-3200', '1939-1293', NULL, '{}', '{"General Psychology"}', '{Psychology}', true, false, '1990-2026', 4.4, 3.3, 67, 'Q2', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.738', '2026-07-18 06:49:00.738', 'A leading family research journal examining family relationships from systems, developmental, and cultural perspectives. It publishes work on couple, parent, and family relationships and the societal challenges families face.', 'Ведущий журнал по семейным исследованиям, рассматривающий семейные отношения с системной, developmental и культурной точек зрения. Публикует работы о партнёрских, родительских и семейных отношениях, а также о социальных вызовах, с которыми сталкиваются семьи.', 'Oilaviy tadqiqotlar bo‘yicha yetakchi jurnal bo‘lib, oilaviy munosabatlarni tizimli, rivojlanish va madaniy nuqtayi nazardan ko‘rib chiqadi. Unda juftlik, ota-ona va oilaviy munosabatlar hamda oilalar duch keladigan ijtimoiy muammolar haqidagi ishlar chop etiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afr8000qw9k15vy3dyzc', 'assessment-and-evaluation-in-higher-education', 'Assessment and Evaluation in Higher Education', 'Оценивание и оценка в высшем образовании', 'Oliy ta’limda baholash va evaluatsiya', 'Международный рецензируемый журнал, посвящённый всем аспектам оценивания и оценки в высшем образовании. Его цель — углублять понимание того, как практики оценки влияют на обучение студентов и качество образования.', 'Taylor & Francis', 'https://www.tandfonline.com/journals/caeh20', NULL, '0260-2938', '1469-297X', NULL, '{}', '{Education}', '{"Social Sciences"}', true, false, '1981-2026', 14.1, 13.2, 98, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.74', '2026-07-18 06:49:00.74', 'An international peer-reviewed journal devoted to all aspects of assessment and evaluation in higher education. Its purpose is to advance understanding of how assessment practices contribute to student learning and educational quality.', 'Международный рецензируемый журнал, посвящённый всем аспектам оценивания и оценки в высшем образовании. Его цель — углублять понимание того, как практики оценки влияют на обучение студентов и качество образования.', 'Oliy ta’limdagi baholash va evaluatsiyaning barcha jihatlariga bag‘ishlangan xalqaro taqrizli jurnal. Uning maqsadi baholash amaliyotlarining talabalar ta’limi va ta’lim sifatiga ta’sirini chuqurroq anglashga yordam berishdir.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afra000rw9k13lbk2xib', 'agrobiological-records', 'Agrobiological Records', 'Агробиологические записи', 'Agrobiologik qaydlar', 'Ежеквартальный журнал, публикующий оригинальные исследования, обзоры, клинические статьи и краткие сообщения в области сельского хозяйства, ветеринарии, зоологии и смежных агробиологических дисциплин.', 'Unique Scientific Publishers', 'https://agrobiologicalrecords.com/', NULL, '2708-7182', '2708-7190', NULL, '{}', '{"Animal Science and Zoology","Agricultural and Biological Sciences (miscellaneous)","Plant Science","Agronomy and Crop Science"}', '{"Agricultural and Biological Sciences"}', true, false, '2023-2026', 4.4, 5.8, 85, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.742', '2026-07-18 06:49:00.742', 'A quarterly journal publishing original research papers, reviews, clinical articles, case reports, and short communications in agriculture, veterinary science, animal science, and allied agrobiological disciplines.', 'Ежеквартальный журнал, публикующий оригинальные исследования, обзоры, клинические статьи и краткие сообщения в области сельского хозяйства, ветеринарии, зоологии и смежных агробиологических дисциплин.', 'Qishloq xo‘jaligi, veterinariya, hayvonotshunoslik va ularga yaqin agrobiologik yo‘nalishlar bo‘yicha original tadqiqotlar, sharhlar, klinik maqolalar va qisqa xabarlarni chop etuvchi choraklik jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afrd000sw9k1irs4y5i1', 'journal-of-language-and-education', 'Journal of Language and Education', 'Журнал языка и образования', 'Til va ta’lim jurnali', 'Высококачественный международный журнал открытого доступа, посвящённый языку и образованию. Публикует эмпирические и теоретические исследования по академическому письму, многоязычию, языковой политике, высшему образованию и современным образовательным практикам.', 'HSE University', 'https://jle.hse.ru/', NULL, NULL, '2411-7390', NULL, '{}', '{"Language and Linguistics","Linguistics and Language",Education}', '{"Arts and Humanities","Social Sciences"}', true, false, '2018-2026', 3.1, 3.5, 86, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.745', '2026-07-18 06:49:00.745', 'A high-quality international open access journal devoted to language and education. It publishes empirical and theoretical research on academic writing, multilingualism, language-related scholarly communication, higher education, and contemporary educational practices.', 'Высококачественный международный журнал открытого доступа, посвящённый языку и образованию. Публикует эмпирические и теоретические исследования по академическому письму, многоязычию, языковой политике, высшему образованию и современным образовательным практикам.', 'Til va ta’limga bag‘ishlangan yuqori sifatli xalqaro open access jurnal. Unda akademik yozuv, ko‘ptillilik, til siyosati, oliy ta’lim va zamonaviy ta’lim amaliyotlariga oid empirik hamda nazariy tadqiqotlar chop etiladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afrf000tw9k14kh481ga', 'journal-of-antimicrobial-chemotherapy', 'Journal of Antimicrobial Chemotherapy', 'Журнал антимикробной химиотерапии', 'Antimikrob kimyoterapiya jurnali', 'Рецензируемый медицинский журнал, публикующий исследования, которые расширяют знания и продвигают науку и практику антимикробной химиотерапии.', 'Oxford University Press', 'https://academic.oup.com/jac', NULL, '0305-7453', '1460-2091', NULL, '{}', '{"Infectious Diseases","Pharmacology (medical)",Pharmacology,"Microbiology (medical)"}', '{Medicine,"Pharmacology, Toxicology and Pharmaceutics"}', true, false, '1975-2026', 6.6, 5.5, 81, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.747', '2026-07-18 06:49:00.747', 'A peer-reviewed medical journal that publishes articles advancing knowledge and the science and application of antimicrobial chemotherapy.', 'Рецензируемый медицинский журнал, публикующий исследования, которые расширяют знания и продвигают науку и практику антимикробной химиотерапии.', 'Antimikrob kimyoterapiya ilm-fani va amaliyotini rivojlantiruvchi hamda bu sohadagi bilimlarni kengaytiruvchi tadqiqotlarni chop etuvchi taqrizli tibbiy jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afrg000uw9k16yuk78sk', 'studies-in-higher-education', 'Studies in Higher Education', 'Исследования в высшем образовании', 'Oliy ta’lim tadqiqotlari', 'Ведущий международный журнал, публикующий исследовательские статьи по проблемам высшего образования. Охватывает вопросы управления, преподавания, обучения и развития систем высшего образования.', 'Taylor & Francis', 'https://www.tandfonline.com/journals/cshe20', NULL, '0307-5079', '1470-174X', NULL, '{}', '{Education}', '{"Social Sciences"}', true, false, '1976-2026', 11.4, 10.1, 96, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.748', '2026-07-18 06:49:00.748', 'A leading international journal publishing research-based articles on higher education issues. It covers teaching, learning, management, and the development of higher education systems.', 'Ведущий международный журнал, публикующий исследовательские статьи по проблемам высшего образования. Охватывает вопросы управления, преподавания, обучения и развития систем высшего образования.', 'Oliy ta’lim masalalariga oid tadqiqot maqolalarini chop etuvchi yetakchi xalqaro jurnal. U boshqaruv, o‘qitish, o‘rganish va oliy ta’lim tizimlari rivojiga doir mavzularni qamrab oladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afri000vw9k15g9goqvr', 'russian-journal-of-economics', 'Russian Journal of Economics', 'Российский журнал экономики', 'Rossiya iqtisodiyot jurnali', 'Рецензируемый журнал открытого доступа, публикующий качественные исследования по всем направлениям экономики, особенно по вопросам экономической политики, институциональных реформ и российской экономики в международном контексте.', 'Non-profit partnership ''Voprosy Ekonomiki''', 'https://rujec.org/', NULL, '2618-7213', '2405-4739', NULL, '{}', '{History,"General Economics, Econometrics and Finance",Finance,"Economics and Econometrics"}', '{"Arts and Humanities","Economics, Econometrics and Finance"}', true, false, '2015-2026', 2.7, 2.4, 96, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.75', '2026-07-18 06:49:00.75', 'An open access peer-reviewed quarterly journal publishing high-quality research across economics, with particular emphasis on economic policy, institutional reform, and the Russian economy in broader international context.', 'Рецензируемый журнал открытого доступа, публикующий качественные исследования по всем направлениям экономики, особенно по вопросам экономической политики, институциональных реформ и российской экономики в международном контексте.', 'Open access taqrizli jurnal bo‘lib, iqtisodiyotning barcha yo‘nalishlari bo‘yicha, ayniqsa iqtisodiy siyosat, institutsional islohotlar va Rossiya iqtisodiyoti haqida xalqaro kontekstdagi sifatli tadqiqotlarni chop etadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afrl000ww9k1ydhbsv6e', 'teaching-and-teacher-education', 'Teaching and Teacher Education', 'Преподавание и педагогическое образование', 'O‘qitish va o‘qituvchilar ta’limi', 'Международный журнал, посвящённый развитию знаний о преподавании как профессиональной практике, педагогическом образовании и подготовке учителей.', 'Elsevier', 'https://www.sciencedirect.com/journal/teaching-and-teacher-education', NULL, '0742-051X', '1879-2480', NULL, '{}', '{Education}', '{"Social Sciences"}', true, false, '1985-2026', 8.5, 6.9, 93, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.753', '2026-07-18 06:49:00.753', 'An international journal dedicated to advancing knowledge on teaching as a professional practice, teacher education, and teacher development.', 'Международный журнал, посвящённый развитию знаний о преподавании как профессиональной практике, педагогическом образовании и подготовке учителей.', 'O‘qitishni professional amaliyot, pedagogik ta’lim va o‘qituvchilar tayyorlash haqidagi bilimlarni rivojlantirishga bag‘ishlangan xalqaro jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afrn000xw9k1nz5xd6ct', 'applied-corpus-linguistics', 'Applied Corpus Linguistics', 'Прикладная корпусная лингвистика', 'Amaliy korpus tilshunosligi', 'Журнал предоставляет площадку для развития теории и практики корпусного анализа, публикации кейсов и обмена методами, инструментами и ресурсами корпусной лингвистики.', 'Elsevier', 'https://www.sciencedirect.com/journal/applied-corpus-linguistics', NULL, NULL, '2666-7991', NULL, '{}', '{"Linguistics and Language","Social Sciences (miscellaneous)"}', '{"Social Sciences"}', true, false, '2021-2026', 4.4, 4.4, 91, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.755', '2026-07-18 06:49:00.755', 'The journal provides a forum for further theorisation of corpus data analysis techniques and for sharing case studies, methods, tools, and resources in corpus linguistics.', 'Журнал предоставляет площадку для развития теории и практики корпусного анализа, публикации кейсов и обмена методами, инструментами и ресурсами корпусной лингвистики.', 'Jurnal korpus tahlili nazariyasi va amaliyotini rivojlantirish, keyslar, metodlar, vositalar va korpus tilshunosligi resurslari almashinuvi uchun maydon yaratadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afrr000yw9k165sm28di', 'international-journal-of-dermatology', 'International Journal of Dermatology', 'Международный журнал дерматологии', 'Xalqaro dermatologiya jurnali', 'Журнал публикует актуальные данные по всем аспектам диагностики и лечения заболеваний кожи. Охватывает клиническую дерматологию, терапию и смежные вопросы практики.', 'John Wiley & Sons', 'https://onlinelibrary.wiley.com/journal/13654632', NULL, '0011-9059', '1365-4632', NULL, '{}', '{Dermatology}', '{Medicine}', true, false, '1963-2026', 5.1, 4.4, 81, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.759', '2026-07-18 06:49:00.759', 'The journal is devoted to publishing current findings and topical data on all aspects of the diagnosis and management of skin disease.', 'Журнал публикует актуальные данные по всем аспектам диагностики и лечения заболеваний кожи. Охватывает клиническую дерматологию, терапию и смежные вопросы практики.', 'Jurnal teri kasalliklarini diagnostika qilish va davolashning barcha jihatlariga oid dolzarb ma’lumotlarni chop etadi. U klinik dermatologiya, terapiya va amaliyotga oid turdosh masalalarni qamrab oladi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afrs000zw9k1i77dacjd', 'journal-of-sustainable-tourism', 'Journal of Sustainable Tourism', 'Журнал устойчивого туризма', 'Barqaror turizm jurnali', 'Международный журнал, публикующий исследования о туризме и устойчивом развитии, включая экономические, социальные, культурные и политические аспекты.', 'Taylor & Francis', 'https://www.tandfonline.com/journals/rsus20', NULL, '0966-9582', '1747-7646', NULL, '{}', '{"Geography, Planning and Development","Tourism, Leisure and Hospitality Management"}', '{"Social Sciences","Business, Management and Accounting"}', true, false, '1993-2026', 22.8, 21.6, 99, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.76', '2026-07-18 06:49:00.76', 'An international journal publishing research on tourism and sustainable development, including economic, social, cultural, and political dimensions.', 'Международный журнал, публикующий исследования о туризме и устойчивом развитии, включая экономические, социальные, культурные и политические аспекты.', 'Turizm va barqaror rivojlanish bo‘yicha iqtisodiy, ijtimoiy, madaniy va siyosiy jihatlarni qamrab oluvchi tadqiqotlarni chop etuvchi xalqaro jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afru0010w9k1qntcmlda', 'journal-of-the-european-academy-of-dermatology-and-venereology', 'Journal of the European Academy of Dermatology and Venereology', 'Журнал Европейской академии дерматологии и венерологии', 'Yevropa dermatologiya va venerologiya akademiyasi jurnali', 'Официальный журнал Европейской академии дерматологии и венерологии, публикующий клинические и научные исследования в области дерматологии, венерологии и смежных направлений.', 'John Wiley & Sons', 'https://onlinelibrary.wiley.com/journal/14683083', NULL, '0926-9959', '1468-3083', NULL, '{}', '{Dermatology,"Infectious Diseases"}', '{Medicine}', true, false, '1991-2026', 13.2, 12.9, 98, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.762', '2026-07-18 06:49:00.762', 'The official journal of the European Academy of Dermatology and Venereology, publishing clinical and scientific research in dermatology, venereology, and related fields.', 'Официальный журнал Европейской академии дерматологии и венерологии, публикующий клинические и научные исследования в области дерматологии, венерологии и смежных направлений.', 'Yevropa Dermatologiya va Venerologiya Akademiyasining rasmiy jurnali bo‘lib, dermatologiya, venerologiya va ularga yaqin yo‘nalishlar bo‘yicha klinik hamda ilmiy tadqiqotlarni chop etadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afrv0011w9k1a5yjejdr', 'journal-of-the-pediatric-infectious-diseases-society', 'Journal of the Pediatric Infectious Diseases Society', 'Журнал общества детских инфекционных болезней', 'Bolalar yuqumli kasalliklari jamiyati jurnali', 'Журнал публикует оригинальные исследования, отчёты о клинических испытаниях, рекомендации, редакционные комментарии и обзоры по детским инфекционным заболеваниям.', 'Oxford University Press', 'https://academic.oup.com/jpids', NULL, '2048-7193', '2048-7207', NULL, '{}', '{"Pediatrics, Perinatology and Child Health","Infectious Diseases"}', '{Medicine}', true, false, '2012-2026', 4.6, 4, 82, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.763', '2026-07-18 06:49:00.763', 'The journal publishes original research articles, clinical trial reports, guidelines, editorial commentaries, and topical reviews in pediatric infectious diseases.', 'Журнал публикует оригинальные исследования, отчёты о клинических испытаниях, рекомендации, редакционные комментарии и обзоры по детским инфекционным заболеваниям.', 'Jurnal bolalar yuqumli kasalliklariga oid original tadqiqotlar, klinik sinov hisobotlari, tavsiyalar, tahririy sharhlar va topical reviewlarni chop etadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afrx0012w9k17o8boob8', 'anz-journal-of-surgery', 'ANZ Journal of Surgery', 'Австрало-новозеландский журнал хирургии', 'Avstraliya va Yangi Zelandiya jarrohlik jurnali', 'Ведущий журнал хирургических исследований Австралии и Новой Зеландии, публикующий оригинальные статьи по клинической практике и исследованиям во всех областях хирургии.', 'John Wiley & Sons', 'https://anzjsurg.onlinelibrary.wiley.com/journal/14452197', NULL, '1445-1433', '1445-2197', NULL, '{}', '{Surgery}', '{Medicine}', true, false, '2001-2026', 2.4, 2, 55, 'Q2', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.765', '2026-07-18 06:49:00.765', 'A leading journal for surgical research in Australia and New Zealand, publishing original articles related to clinical practice and research in all fields of surgery.', 'Ведущий журнал хирургических исследований Австралии и Новой Зеландии, публикующий оригинальные статьи по клинической практике и исследованиям во всех областях хирургии.', 'Avstraliya va Yangi Zelandiyadagi jarrohlik tadqiqotlari bo‘yicha yetakchi jurnal bo‘lib, jarrohlikning barcha yo‘nalishlarida klinik amaliyot va tadqiqotlarga oid original maqolalarni chop etadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afrz0013w9k13a4w50cq', 'turkish-journal-of-physical-medicine-and-rehabilitation', 'Turkish Journal of Physical Medicine and Rehabilitation', 'Турецкий журнал физической и реабилитационной медицины', 'Turk jismoniy va reabilitatsion tibbiyot jurnali', 'Международный журнал открытого доступа с двойным слепым рецензированием, публикующий новейшие разработки по всем аспектам физической и реабилитационной медицины.', 'Turkish Society of Physical Medicine and Rehabilitation', 'https://www.ftrdergisi.com/', NULL, '2587-0823', '2587-1250', NULL, '{}', '{Rehabilitation,"Physical Therapy, Sports Therapy and Rehabilitation"}', '{Medicine,"Health Professions"}', true, false, '2018-2026', 2.3, 2.1, 54, 'Q2', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.767', '2026-07-18 06:49:00.767', 'An international open access, double-blind peer-reviewed journal bringing the latest developments in all aspects of physical medicine and rehabilitation.', 'Международный журнал открытого доступа с двойным слепым рецензированием, публикующий новейшие разработки по всем аспектам физической и реабилитационной медицины.', 'Jismoniy va reabilitatsion tibbiyotning barcha jihatlari bo‘yicha eng so‘nggi ishlanmalarni chop etuvchi xalqaro, open access, ikki tomonlama ko‘r taqrizli jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afs00014w9k14m3vp0b7', 'annals-of-physical-and-rehabilitation-medicine', 'Annals of Physical and Rehabilitation Medicine', 'Анналы физической и реабилитационной медицины', 'Jismoniy va reabilitatsiya tibbiyoti annallari', 'Рецензируемый журнал по физической и реабилитационной медицине, публикующий клинические исследования, работы по методам оценки и вопросам реабилитационной практики.', 'Elsevier', 'https://www.sciencedirect.com/journal/annals-of-physical-and-rehabilitation-medicine', NULL, '1877-0657', '1877-0665', NULL, '{}', '{Rehabilitation,"Orthopedics and Sports Medicine"}', '{Medicine}', true, false, '2009-2026', 8.9, 5.3, 99, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.768', '2026-07-18 06:49:00.768', 'A peer-reviewed journal covering physical medicine and rehabilitation, including clinical research, evaluation methods, and rehabilitation practice.', 'Рецензируемый журнал по физической и реабилитационной медицине, публикующий клинические исследования, работы по методам оценки и вопросам реабилитационной практики.', 'Jismoniy va reabilitatsiya tibbiyotiga bag‘ishlangan, klinik tadqiqotlar, baholash usullari va reabilitatsiya amaliyotini yorituvchi taqrizlanadigan jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afs10015w9k1y45nkq29', 'journal-of-baltic-science-education', 'Journal of Baltic Science Education', 'Журнал балтийского научного образования', 'Boltiq ilmiy ta’lim jurnali', 'Международный журнал открытого доступа, публикующий теоретические, экспериментальные и методические исследования в области естественно-научного образования на всех уровнях обучения.', 'Scientia Socialis Ltd', 'https://www.scientiasocialis.lt/jbse/', NULL, '1648-3898', '2538-7138', NULL, '{}', '{Education}', '{"Social Sciences"}', true, false, '2008-2026', 2.5, 2.7, 55, 'Q2', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.769', '2026-07-18 06:49:00.769', 'An international open access journal publishing theoretical, experimental, and methodological studies in science education across all educational levels.', 'Международный журнал открытого доступа, публикующий теоретические, экспериментальные и методические исследования в области естественно-научного образования на всех уровнях обучения.', 'Barcha ta’lim bosqichlarida tabiiy fanlar ta’limi bo‘yicha nazariy, eksperimental va metodik tadqiqotlarni chop etuvchi xalqaro ochiq kirish jurnali.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afs30016w9k1q60tax85', 'journal-of-tourism-and-cultural-change', 'Journal of Tourism and Cultural Change', 'Журнал туризма и культурных изменений', 'Turizm va madaniy o‘zgarishlar jurnali', 'Рецензируемый междисциплинарный журнал, посвящённый изучению связей, противоречий и трансформаций между туризмом, путешествиями и культурой в глобальном контексте.', 'Taylor & Francis', 'https://www.tandfonline.com/journals/rtcc20', NULL, '1476-6825', '1747-7654', NULL, '{}', '{"Cultural Studies","Nature and Landscape Conservation","Geography, Planning and Development",Transportation,"Tourism, Leisure and Hospitality Management"}', '{"Social Sciences","Environmental Science","Business, Management and Accounting"}', true, false, '2003-2026', 6.4, 3.8, 98, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.771', '2026-07-18 06:49:00.771', 'A peer-reviewed transdisciplinary journal examining relationships, tensions, and transformations between tourism, travel, and culture in global contexts.', 'Рецензируемый междисциплинарный журнал, посвящённый изучению связей, противоречий и трансформаций между туризмом, путешествиями и культурой в глобальном контексте.', 'Turizm, sayohat va madaniyat o‘rtasidagi aloqalar, ziddiyatlar va o‘zgarishlarni global kontekstda tahlil qiluvchi taqrizlanadigan fanlararo jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afs50017w9k1givp2gx5', 'translation-studies', 'Translation Studies', 'Исследования перевода', 'Tarjimashunoslik tadqiqotlari', 'Журнал по переводоведению, расширяющий методологии и концептуальные рамки дисциплины и рассматривающий исторические, социальные, институциональные и культурные аспекты перевода.', 'Taylor & Francis', 'https://www.tandfonline.com/journals/rtrs20', NULL, '1478-1700', '1751-2921', NULL, '{}', '{"Language and Linguistics","Linguistics and Language"}', '{"Arts and Humanities","Social Sciences"}', true, false, '2008-2026', 2.7, 3.3, 84, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.773', '2026-07-18 06:49:00.773', 'A journal devoted to translation studies, expanding methodologies and conceptual frameworks while exploring historical, social, institutional, and cultural dimensions of translation.', 'Журнал по переводоведению, расширяющий методологии и концептуальные рамки дисциплины и рассматривающий исторические, социальные, институциональные и культурные аспекты перевода.', 'Tarjimashunoslikka bag‘ishlangan jurnal bo‘lib, metodologiyalar va konseptual yondashuvlarni kengaytiradi hamda tarjimaning tarixiy, ijtimoiy, institutsional va madaniy jihatlarini yoritadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsm001gw9k1ehtycxuj', 'transportation-research-part-e-logistics-and-transportation-review', 'Transportation Research Part E: Logistics and Transportation Review', 'Transportation Research Part E: Логистика и транспортный обзор', 'Transportation Research Part E: Logistika va transport sharhi', 'Рецензируемый журнал, публикующий качественные исследования в области логистики, грузовых перевозок, транспортных систем, а также связанных с ними вопросов управления и политики.', 'Elsevier', 'https://www.sciencedirect.com/journal/transportation-research-part-e-logistics-and-transportation-review', NULL, '1366-5545', '1878-5794', NULL, '{}', '{"Civil and Structural Engineering",Transportation,"Business and International Management"}', '{Engineering,"Social Sciences","Business, Management and Accounting"}', true, false, '1997-2026', 14, 11.2, 95, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.79', '2026-07-18 06:49:00.79', 'A peer-reviewed journal publishing high-quality research across logistics, freight transport, transportation systems, and related management and policy issues.', 'Рецензируемый журнал, публикующий качественные исследования в области логистики, грузовых перевозок, транспортных систем, а также связанных с ними вопросов управления и политики.', 'Logistika, yuk tashish, transport tizimlari hamda ular bilan bog‘liq boshqaruv va siyosat masalalari bo‘yicha sifatli tadqiqotlarni chop etuvchi taqrizlanadigan jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsr001hw9k1q1ir6icn', 'chemical-science', 'Chemical Science', 'Химическая наука', 'Kimyo fani', 'Флагманский журнал открытого доступа Королевского химического общества, охватывающий весь спектр химических наук и публикующий смелые междисциплинарные исследования высокого уровня.', 'Royal Society of Chemistry', 'https://www.rsc.org/publishing/journals/chemical-science', NULL, '2041-6520', '2041-6539', NULL, '{}', '{"General Chemistry"}', '{Chemistry}', true, false, '2010-2026', 12, 10.9, 89, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.795', '2026-07-18 06:49:00.795', 'The flagship open access journal of the Royal Society of Chemistry, covering the full breadth of the chemical sciences and publishing bold, high-impact interdisciplinary research.', 'Флагманский журнал открытого доступа Королевского химического общества, охватывающий весь спектр химических наук и публикующий смелые междисциплинарные исследования высокого уровня.', 'Qirollik Kimyo Jamiyatining flagman ochiq kirish jurnali bo‘lib, kimyo fanlarining barcha yo‘nalishlarini qamrab oladi va yuqori ta’sirga ega fanlararo tadqiqotlarni nashr etadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afss001iw9k1ozze33qn', 'maternal-and-child-health-journal', 'Maternal and Child Health Journal', 'Журнал материнского и детского здоровья', 'Ona va bola salomatligi jurnali', 'Журнал, направленный на развитие научных и профессиональных знаний в области охраны здоровья матери и ребёнка через публикацию исследований, обзоров и материалов, значимых для политики здравоохранения.', 'Springer Nature', 'https://link.springer.com/journal/10995', NULL, '1092-7875', '1573-6628', NULL, '{}', '{"Pediatrics, Perinatology and Child Health","Obstetrics and Gynecology","Public Health, Environmental and Occupational Health",Epidemiology}', '{Medicine}', true, false, '1997-2026', 3.8, 3, 72, 'Q2', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.796', '2026-07-18 06:49:00.796', 'A journal devoted to advancing scientific and professional knowledge in maternal and child health through research, reviews, and policy-relevant studies.', 'Журнал, направленный на развитие научных и профессиональных знаний в области охраны здоровья матери и ребёнка через публикацию исследований, обзоров и материалов, значимых для политики здравоохранения.', 'Onalar va bolalar salomatligi sohasidagi ilmiy hamda amaliy bilimlarni rivojlantirishga qaratilgan, tadqiqotlar, sharhlar va siyosat uchun muhim materiallarni nashr etuvchi jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afst001jw9k1cpq8ub02', 'educational-technology-research-and-development', 'Educational Technology Research and Development', 'Исследования и разработки в области образовательных технологий', 'Ta’lim texnologiyalari bo‘yicha tadqiqotlar va ishlanmalar', 'Научный журнал, посвящённый исследованиям и разработкам в области образовательных технологий, включая instructional design, учебные среды и технологии, поддерживающие обучение.', 'Springer Nature', 'https://link.springer.com/journal/11423', NULL, '1042-1629', '1556-6501', NULL, '{}', '{Education}', '{"Social Sciences"}', true, false, '1957, 1989-2026', 10.7, 11.3, 96, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.797', '2026-07-18 06:49:00.797', 'A scholarly journal focused on research and development in educational technology, including instructional design, learning environments, and technology-enhanced education.', 'Научный журнал, посвящённый исследованиям и разработкам в области образовательных технологий, включая instructional design, учебные среды и технологии, поддерживающие обучение.', 'Ta’lim texnologiyalari, instructional design, o‘quv muhitlari va texnologiya bilan boyitilgan ta’lim bo‘yicha tadqiqotlar hamda ishlanmalarga bag‘ishlangan ilmiy jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsv001kw9k1xw7qtcb5', 'international-journal-of-society-culture-and-language', 'International Journal of Society, Culture and Language', 'Международный журнал общества, культуры и языка', 'Jamiyat, madaniyat va til xalqaro jurnali', 'Полностью рецензируемый журнал открытого доступа, публикующий оригинальные исследования и обзоры о взаимосвязях общества, культуры и языка, значимые для лингвистики, антропологии, образования и межкультурных исследований.', 'Lulu Press Inc', 'https://www.ijscl.com/', NULL, NULL, '2329-2210', NULL, '{}', '{Anthropology,"Linguistics and Language","Gender Studies",Education}', '{"Social Sciences"}', true, false, '2019-2026', 3.8, 3.5, 91, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.799', '2026-07-18 06:49:00.799', 'A fully peer-reviewed open access journal publishing original research and reviews on the relationships between society, culture, and language, with practical relevance for linguistics, anthropology, education, and intercultural studies.', 'Полностью рецензируемый журнал открытого доступа, публикующий оригинальные исследования и обзоры о взаимосвязях общества, культуры и языка, значимые для лингвистики, антропологии, образования и межкультурных исследований.', 'Jamiyat, madaniyat va til o‘rtasidagi bog‘liqliklar haqida original tadqiqotlar va sharhlarni nashr etuvchi, tilshunoslik, antropologiya, ta’lim va madaniyatlararo tadqiqotlar uchun amaliy ahamiyatga ega ochiq kirishdagi to‘liq taqrizlanadigan jurnal.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsw001lw9k1ff18da47', '3l-language-linguistics-literature', '3L: Language, Linguistics, Literature', '3L: Язык, лингвистика, литература', '3L: Til, tilshunoslik, adabiyot', 'Международный рецензируемый журнал издательства UKM Press, рассматривающий ключевые вопросы языка, лингвистики, литературы и английских языковых исследований, особенно в многоязычных контекстах.', 'Penerbit Universiti Kebangsaan Malaysia', 'https://ejournal.ukm.my/3l', NULL, '0128-5157', '2550-2247', NULL, '{}', '{"Literature and Literary Theory","Language and Linguistics","Linguistics and Language"}', '{"Arts and Humanities","Social Sciences"}', true, false, '2008-2026', 1.6, 1.3, 97, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.8', '2026-07-18 06:49:00.8', 'A peer-reviewed international journal published by UKM Press that explores key issues in language, linguistics, literature, and English language studies, especially in multilingual contexts.', 'Международный рецензируемый журнал издательства UKM Press, рассматривающий ключевые вопросы языка, лингвистики, литературы и английских языковых исследований, особенно в многоязычных контекстах.', 'UKM Press tomonidan nashr etiladigan xalqaro taqrizlanadigan jurnal bo‘lib, til, tilshunoslik, adabiyot va ingliz tili tadqiqotlarining asosiy masalalarini, ayniqsa ko‘p tilli kontekstlarda, yoritadi.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsy001mw9k1p8rgqrok', 'australasian-accounting-business-and-finance-journal', 'Australasian Accounting, Business and Finance Journal', 'Австралазийский журнал бухгалтерского учёта, бизнеса и финансов', 'Avstralaziya buxgalteriya hisobi, biznes va moliya jurnali', 'Двухсторонне слепо рецензируемый журнал открытого доступа, публикующий междисциплинарные исследования в области бухгалтерского учёта, бизнеса, финансов и финансового планирования.', 'University of Wollongong', 'https://www.uowoajournals.org/aabfj/', NULL, '1834-2000', '1834-2019', NULL, '{}', '{Finance,"General Business, Management and Accounting"}', '{"Economics, Econometrics and Finance","Business, Management and Accounting"}', true, false, '2014-2026', 4.9, 3.3, 70, 'Q2', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.802', '2026-07-18 06:49:00.802', 'A double-blind peer-reviewed open access journal publishing interdisciplinary research across accounting, business, finance, and financial planning.', 'Двухсторонне слепо рецензируемый журнал открытого доступа, публикующий междисциплинарные исследования в области бухгалтерского учёта, бизнеса, финансов и финансового планирования.', 'Buxgalteriya hisobi, biznes, moliya va moliyaviy rejalashtirish bo‘yicha fanlararo tadqiqotlarni chop etuvchi ikki tomonlama anonim taqrizli ochiq kirish jurnali.');
INSERT INTO public."Journal" (id, slug, title, "titleRu", "titleUz", "shortDescription", publisher, website, "coverImage", issn, eissn, country, languages, "subjectAreas", categories, "isScopusIndexed", "isOakRecommended", "scopusCoverageYears", citescore2025, citescore2026, percentile, quartile, "verificationStatus", "telegramUrl", "submissionUrl", "createdAt", "updatedAt", "shortDescriptionEn", "shortDescriptionRu", "shortDescriptionUz") VALUES ('cmrq0afsz001nw9k1h68i8woo', 'fermentation', 'Fermentation', 'Ферментация', 'Fermentatsiya', 'Международный рецензируемый журнал открытого доступа, посвящённый процессам ферментации, технологиям ферментации и их применениям в биотехнологии, пищевой науке и микробиологии.', 'MDPI', 'https://www.mdpi.com/journal/fermentation', NULL, NULL, '2311-5637', NULL, '{}', '{"Plant Science","Biochemistry, Genetics and Molecular Biology (miscellaneous)","Food Science"}', '{"Agricultural and Biological Sciences","Biochemistry, Genetics and Molecular Biology"}', true, false, '2015-2026', 7.7, 7.7, 88, 'Q1', 'VERIFIED', NULL, NULL, '2026-07-18 06:49:00.803', '2026-07-18 06:49:00.803', 'An international peer-reviewed open access journal focused on fermentation processes, fermentation technology, and related applications in biotechnology, food science, and microbiology.', 'Международный рецензируемый журнал открытого доступа, посвящённый процессам ферментации, технологиям ферментации и их применениям в биотехнологии, пищевой науке и микробиологии.', 'Fermentatsiya jarayonlari, fermentatsiya texnologiyasi hamda ularning biotexnologiya, oziq-ovqat fani va mikrobiologiyadagi qo‘llanishlariga bag‘ishlangan xalqaro taqrizlanadigan ochiq kirish jurnali.');
